const aliases: Record<string, string> = {
  'apple tv': 'atv', tvos: 'atv', apple: 'ios', iphone: 'ios', ipad: 'ios',
  osx: 'macos', mac: 'macos', edge: 'msedge', 'microsoft edge': 'msedge',
  'internet explorer': 'ie', 'google chrome': 'chrome', 'google tv': 'gtv',
  tizen: 'samsung', 'smart tv': 'samsung', 'wii u': 'wiiu',
  amazon: 'alexa', 'fire tv': 'alexa', plexamp: 'plexamp',
};

export function getPlatformIcon(platform?: string): string | null {
  if (!platform) return icons.default ?? null;
  const p = platform.toLowerCase().trim();
  if (icons[p]) return icons[p];
  for (const [alias, key] of Object.entries(aliases)) {
    if (p.includes(alias)) return icons[key] ?? null;
  }
  for (const key of Object.keys(icons)) {
    if (p.includes(key)) return icons[key];
  }
  return icons.default ?? null;
}
